INSERT INTO public.enemies (slug, name, source, data) VALUES ('aboleth','Aboleth','SRD','{"sizeType":"Large aberration, lawful evil","armorClass":{"value":17,"note":"natural"},"hitPoints":{"average":135,"formula":"18d10+36"},"speed":"10 ft., swim 40 ft.","abilityScores":{"str":21,"dex":9,"con":15,"int":18,"wis":15,"cha":18},"skills":[{"name":"History","bonus":12},{"name":"Perception","bonus":10}],"senses":"darkvision 120 ft., passive Perception 20","languages":"Deep Speech, telepathy 120 ft.","challengeRating":"10","xp":5900,"proficiencyBonus":4,"traits":[{"name":"Amphibious","description":"The aboleth can breathe air and water."},{"name":"Mucous Cloud","description":"While underwater, the aboleth is surrounded by transformative mucus. A creature that touches the aboleth or that hits it with a melee attack while within 5 ft. of it must make a DC 14 Constitution saving throw. On a failure, the creature is diseased for 1d4 hours. The diseased creature can breathe only underwater."},{"name":"Probing Telepathy","description":"If a creature communicates telepathically with the aboleth, the aboleth learns the creature''s greatest desires if the aboleth can see the creature."}],"actions":[{"name":"Multiattack","description":"The aboleth makes three tentacle attacks."},{"name":"Tentacle","description":"Melee Weapon Attack: +9 to hit, reach 10 ft., one target. Hit: 12 (2d6 + 5) bludgeoning damage. If the target is a creature, it must succeed on a DC 14 Constitution saving throw or become diseased. The disease has no effect for 1 minute and can be removed by any magic that cures disease. After 1 minute, the diseased creature''s skin becomes translucent and slimy, the creature can''t regain hit points unless it is underwater, and the disease can be removed only by heal or another disease-curing spell of 6th level or higher. When the creature is outside a body of water, it takes 6 (1d12) acid damage every 10 minutes unless moisture is applied to the skin before 10 minutes have passed."},{"name":"Tail","description":"Melee Weapon Attack: +9 to hit, reach 10 ft., one target. Hit: 15 (3d6 + 5) bludgeoning damage."},{"name":"Enslave","description":"The aboleth targets one creature it can see within 30 ft. of it. The target must succeed on a DC 14 Wisdom saving throw or be magically charmed by the aboleth until the aboleth dies or until it is on a different plane of existence from the target. The charmed target is under the aboleth''s control and can''t take reactions, and the aboleth and the target can communicate telepathically with each other over any distance.\nWhenever the charmed target takes damage, the target can repeat the saving throw. On a success, the effect ends. No more than once every 24 hours, the target can also repeat the saving throw when it is at least 1 mile away from the aboleth."},{"name":"Detect","description":"The aboleth makes a Wisdom (Perception) check."},{"name":"Tail Swipe","description":"The aboleth makes one tail attack."},{"name":"Psychic Drain (Costs 2 Actions)","description":"One creature charmed by the aboleth takes 10 (3d6) psychic damage, and the aboleth regains hit points equal to the damage the creature takes."}],"description":"","tags":["Aberration"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('acolyte','Acolyte','SRD','{"sizeType":"Medium humanoid (any race), any alignment","armorClass":{"value":10,"note":"natural armor"},"hitPoints":{"average":9,"formula":"2d8"},"speed":"30 ft.","abilityScores":{"str":10,"dex":10,"con":10,"int":10,"wis":14,"cha":11},"skills":[{"name":"Medicine","bonus":4},{"name":"Religion","bonus":2}],"senses":"passive Perception 12","languages":"any one language (usually Common)","challengeRating":"1/4","xp":50,"proficiencyBonus":2,"traits":[{"name":"Spellcasting","description":"The acolyte is a 1st-level spellcaster. Its spellcasting ability is Wisdom (spell save DC 12, +4 to hit with spell attacks). The acolyte has following cleric spells prepared:\n\n- Cantrips (at will): light, sacred flame, thaumaturgy\n- 1st level (3 slots): bless, cure wounds, sanctuary"}],"actions":[{"name":"Club","description":"Melee Weapon Attack: +2 to hit, reach 5 ft., one target. Hit: 2 (1d4) bludgeoning damage."}],"description":"Acolytes are junior members of a clergy, usually answerable to a priest. They perform a variety of functions in a temple and are granted minor spellcasting power by their deities.","tags":["Humanoid","Any race","Chult","ToA"],"habitat":"CHULT","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-black-dragon','Adult Black Dragon','SRD','{"sizeType":"Huge dragon, chaotic evil","armorClass":{"value":19,"note":"natural"},"hitPoints":{"average":195,"formula":"17d12+85"},"speed":"40 ft., fly 80 ft., swim 40 ft.","abilityScores":{"str":23,"dex":14,"con":21,"int":14,"wis":13,"cha":17},"skills":[{"name":"Perception","bonus":11},{"name":"Stealth","bonus":7}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 21","languages":"Common, Draconic","challengeRating":"14","xp":11500,"proficiencyBonus":5,"traits":[{"name":"Amphibious","description":"The dragon can breathe air and water."},{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +11 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage plus 4 (1d8) acid damage."},{"name":"Claw","description":"Melee Weapon Attack: +11 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +11 to hit, reach 15 ft., one target. Hit: 15 (2d8 + 6) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 16 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Acid Breath","description":"The dragon exhales acid in a 60-foot line that is 5 feet wide. Each creature in that line must make a DC 18 Dexterity saving throw, taking 54 (12d8) acid damage on a failed save, or half as much damage on a successful one."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 19 Dexterity saving throw or take 13 (2d6 + 6) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-blue-dragon','Adult Blue Dragon','SRD','{"sizeType":"Huge dragon, lawful evil","armorClass":{"value":19,"note":"natural"},"hitPoints":{"average":225,"formula":"18d12+108"},"speed":"40 ft., burrow 30 ft., fly 80 ft.","abilityScores":{"str":25,"dex":10,"con":23,"int":16,"wis":15,"cha":19},"skills":[{"name":"Perception","bonus":12},{"name":"Stealth","bonus":5}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 22","languages":"Common, Draconic","challengeRating":"16","xp":15000,"proficiencyBonus":5,"traits":[{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +12 to hit, reach 10 ft., one target. Hit: 18 (2d10 + 7) piercing damage plus 5 (1d10) lightning damage."},{"name":"Claw","description":"Melee Weapon Attack: +12 to hit, reach 5 ft., one target. Hit: 14 (2d6 + 7) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +12 to hit, reach 15 ft., one target. Hit: 16 (2d8 + 7) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 ft. of the dragon and aware of it must succeed on a DC 17 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Lightning Breath","description":"The dragon exhales lightning in a 90-foot line that is 5 ft. wide. Each creature in that line must make a DC 19 Dexterity saving throw, taking 66 (12d10) lightning damage on a failed save, or half as much damage on a successful one."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 20 Dexterity saving throw or take 14 (2d6 + 7) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-brass-dragon','Adult Brass Dragon','SRD','{"sizeType":"Huge dragon, chaotic good","armorClass":{"value":18,"note":"natural"},"hitPoints":{"average":172,"formula":"15d12+75"},"speed":"40 ft., burrow 40 ft., fly 80 ft.","abilityScores":{"str":23,"dex":10,"con":21,"int":14,"wis":13,"cha":17},"skills":[{"name":"History","bonus":7},{"name":"Perception","bonus":11},{"name":"Persuasion","bonus":8},{"name":"Stealth","bonus":5}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 21","languages":"Common, Draconic","challengeRating":"13","xp":10000,"proficiencyBonus":5,"traits":[{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +11 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +11 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +11 to hit, reach 15 ft., one target. Hit: 15 (2d8 + 6) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 16 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours ."},{"name":"Breath Weapons","description":"The dragon uses one of the following breath weapons.\nFire Breath. The dragon exhales fire in an 60-foot line that is 5 feet wide. Each creature in that line must make a DC 18 Dexterity saving throw, taking 45 (13d6) fire damage on a failed save, or half as much damage on a successful one.\nSleep Breath. The dragon exhales sleep gas in a 60-foot cone. Each creature in that area must succeed on a DC 18 Constitution saving throw or fall unconscious for 10 minutes. This effect ends for a creature if the creature takes damage or someone uses an action to wake it."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 19 Dexterity saving throw or take 13 (2d6 + 6) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-bronze-dragon','Adult Bronze Dragon','SRD','{"sizeType":"Huge dragon, lawful good","armorClass":{"value":19,"note":"natural"},"hitPoints":{"average":212,"formula":"17d12+102"},"speed":"40 ft., fly 80 ft., swim 40 ft.","abilityScores":{"str":25,"dex":10,"con":23,"int":16,"wis":15,"cha":19},"skills":[{"name":"Insight","bonus":7},{"name":"Perception","bonus":12},{"name":"Stealth","bonus":5}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 22","languages":"Common, Draconic","challengeRating":"15","xp":13000,"proficiencyBonus":5,"traits":[{"name":"Amphibious","description":"The dragon can breathe air and water."},{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +12 to hit, reach 10 ft., one target. Hit: 18 (2d10 + 7) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +12 to hit, reach 5 ft., one target. Hit: 14 (2d6 + 7) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +12 to hit, reach 15 ft., one target. Hit: 16 (2d8 + 7) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 17 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Breath Weapons","description":"The dragon uses one of the following breath weapons.\nLightning Breath. The dragon exhales lightning in a 90-foot line that is 5 feet wide. Each creature in that line must make a DC 19 Dexterity saving throw, taking 66 (12d10) lightning damage on a failed save, or half as much damage on a successful one.\nRepulsion Breath. The dragon exhales repulsion energy in a 30-foot cone. Each creature in that area must succeed on a DC 19 Strength saving throw. On a failed save, the creature is pushed 60 feet away from the dragon."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 20 Dexterity saving throw or take 14 (2d6 + 7) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-copper-dragon','Adult Copper Dragon','SRD','{"sizeType":"Huge dragon, chaotic good","armorClass":{"value":18,"note":"natural"},"hitPoints":{"average":184,"formula":"16d12+80"},"speed":"40 ft., climb 40 ft., fly 80 ft.","abilityScores":{"str":23,"dex":12,"con":21,"int":18,"wis":15,"cha":17},"skills":[{"name":"Deception","bonus":8},{"name":"Perception","bonus":12},{"name":"Stealth","bonus":6}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 22","languages":"Common, Draconic","challengeRating":"14","xp":11500,"proficiencyBonus":5,"traits":[{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +11 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +11 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +11 to hit, reach 15 ft., one target. Hit: 15 (2d8 + 6) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 16 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Breath Weapons","description":"The dragon uses one of the following breath weapons.\nAcid Breath. The dragon exhales acid in an 60-foot line that is 5 feet wide. Each creature in that line must make a DC 18 Dexterity saving throw, taking 54 (12d8) acid damage on a failed save, or half as much damage on a successful one.\nSlowing Breath. The dragon exhales gas in a 60-foot cone. Each creature in that area must succeed on a DC 18 Constitution saving throw. On a failed save, the creature can''t use reactions, its speed is halved, and it can''t make more than one attack on its turn. In addition, the creature can use either an action or a bonus action on its turn, but not both. These effects last for 1 minute. The creature can repeat the saving throw at the end of each of its turns, ending the effect on itself with a successful save."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 19 Dexterity saving throw or take 13 (2d6 + 6) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-gold-dragon','Adult Gold Dragon','SRD','{"sizeType":"Huge dragon, lawful good","armorClass":{"value":19,"note":"natural"},"hitPoints":{"average":256,"formula":"19d12+133"},"speed":"40 ft., fly 80 ft., swim 40 ft.","abilityScores":{"str":27,"dex":14,"con":25,"int":16,"wis":15,"cha":24},"skills":[{"name":"Insight","bonus":8},{"name":"Perception","bonus":14},{"name":"Persuasion","bonus":13},{"name":"Stealth","bonus":8}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 24","languages":"Common, Draconic","challengeRating":"17","xp":18000,"proficiencyBonus":6,"traits":[{"name":"Amphibious","description":"The dragon can breathe air and water."},{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +14 to hit, reach 10 ft., one target. Hit: 19 (2d10 + 8) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +14 to hit, reach 5 ft., one target. Hit: 15 (2d6 + 8) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +14 to hit, reach 15 ft., one target. Hit: 17 (2d8 + 8) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 21 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Breath Weapons","description":"The dragon uses one of the following breath weapons.\nFire Breath. The dragon exhales fire in a 60-foot cone. Each creature in that area must make a DC 21 Dexterity saving throw, taking 66 (12d10) fire damage on a failed save, or half as much damage on a successful one.\nWeakening Breath. The dragon exhales gas in a 60-foot cone. Each creature in that area must succeed on a DC 21 Strength saving throw or have disadvantage on Strength-based attack rolls, Strength checks, and Strength saving throws for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 22 Dexterity saving throw or take 15 (2d6 + 8) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
