INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-red-dragon','Adult Red Dragon','SRD','{"sizeType":"Huge dragon, chaotic evil","armorClass":{"value":19,"note":"natural"},"hitPoints":{"average":256,"formula":"19d12+133"},"speed":"40 ft., climb 40 ft., fly 80 ft.","abilityScores":{"str":27,"dex":10,"con":25,"int":16,"wis":13,"cha":21},"skills":[{"name":"Perception","bonus":13},{"name":"Stealth","bonus":6}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 23","languages":"Common, Draconic","challengeRating":"17","xp":18000,"proficiencyBonus":6,"traits":[{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +14 to hit, reach 10 ft., one target. Hit: 19 (2d10 + 8) piercing damage plus 7 (2d6) fire damage."},{"name":"Claw","description":"Melee Weapon Attack: +14 to hit, reach 5 ft., one target. Hit: 15 (2d6 + 8) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +14 to hit, reach 15 ft., one target. Hit: 17 (2d8 + 8) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 ft. of the dragon and aware of it must succeed on a DC 19 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Fire Breath","description":"The dragon exhales fire in a 60-foot cone. Each creature in that area must make a DC 21 Dexterity saving throw, taking 63 (18d6) fire damage on a failed save, or half as much damage on a successful one."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 22 Dexterity saving throw or take 15 (2d6 + 8) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-silver-dragon','Adult Silver Dragon','SRD','{"sizeType":"Huge dragon, lawful good","armorClass":{"value":19,"note":"natural"},"hitPoints":{"average":243,"formula":"18d12+126"},"speed":"40 ft., fly 80 ft.","abilityScores":{"str":27,"dex":10,"con":25,"int":16,"wis":13,"cha":21},"skills":[{"name":"Arcana","bonus":8},{"name":"History","bonus":8},{"name":"Perception","bonus":11},{"name":"Stealth","bonus":5}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 21","languages":"Common, Draconic","challengeRating":"16","xp":15000,"proficiencyBonus":5,"traits":[{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +13 to hit, reach 10 ft., one target. Hit: 19 (2d10 + 8) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +13 to hit, reach 5 ft., one target. Hit: 15 (2d6 + 8) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +13 to hit, reach 15 ft., one target. Hit: 17 (2d8 + 8) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 18 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Breath Weapons","description":"The dragon uses one of the following breath weapons.\nCold Breath. The dragon exhales an icy blast in a 60-foot cone. Each creature in that area must make a DC 20 Constitution saving throw, taking 58 (13d8) cold damage on a failed save, or half as much damage on a successful one.\nParalyzing Breath. The dragon exhales paralyzing gas in a 60-foot cone. Each creature in that area must succeed on a DC 20 Constitution saving throw or be paralyzed for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 22 Dexterity saving throw or take 15 (2d6 + 8) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('adult-white-dragon','Adult White Dragon','SRD','{"sizeType":"Huge dragon, chaotic evil","armorClass":{"value":18,"note":"natural"},"hitPoints":{"average":200,"formula":"16d12+96"},"speed":"40 ft., burrow 30 ft., fly 80 ft., swim 40 ft.","abilityScores":{"str":22,"dex":10,"con":22,"int":8,"wis":12,"cha":12},"skills":[{"name":"Perception","bonus":11},{"name":"Stealth","bonus":5}],"senses":"darkvision 120 ft., blindsight 60 ft., passive Perception 21","languages":"Common, Draconic","challengeRating":"13","xp":10000,"proficiencyBonus":5,"traits":[{"name":"Ice Walk","description":"The dragon can move across and climb icy surfaces without needing to make an ability check. Additionally, difficult terrain composed of ice or snow doesn''t cost it extra movement."},{"name":"Legendary Resistance","description":"If the dragon fails a saving throw, it can choose to succeed instead."}],"actions":[{"name":"Multiattack","description":"The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +11 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage plus 4 (1d8) cold damage."},{"name":"Claw","description":"Melee Weapon Attack: +11 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage."},{"name":"Tail","description":"Melee Weapon Attack: +11 to hit, reach 15 ft., one target. Hit: 15 (2d8 + 6) bludgeoning damage."},{"name":"Frightful Presence","description":"Each creature of the dragon''s choice that is within 120 ft. of the dragon and aware of it must succeed on a DC 14 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours."},{"name":"Cold Breath","description":"The dragon exhales an icy blast in a 60-foot cone. Each creature in that area must make a DC 19 Constitution saving throw, taking 54 (12d8) cold damage on a failed save, or half as much damage on a successful one."},{"name":"Detect","description":"The dragon makes a Wisdom (Perception) check."},{"name":"Tail Attack","description":"The dragon makes a tail attack."},{"name":"Wing Attack (Costs 2 Actions)","description":"The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 19 Dexterity saving throw or take 13 (2d6 + 6) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('air-elemental','Air Elemental','SRD','{"sizeType":"Large elemental, neutral","armorClass":{"value":15,"note":"natural armor"},"hitPoints":{"average":90,"formula":"12d10+24"},"speed":"fly 90 ft., hover true","abilityScores":{"str":14,"dex":20,"con":14,"int":6,"wis":10,"cha":6},"skills":[],"senses":"darkvision 60 ft., passive Perception 10","languages":"Auran","challengeRating":"5","xp":1800,"proficiencyBonus":3,"traits":[{"name":"Air Form","description":"The elemental can enter a hostile creature''s space and stop there. It can move through a space as narrow as 1 inch wide without squeezing."}],"actions":[{"name":"Multiattack","description":"The elemental makes two slam attacks."},{"name":"Slam","description":"Melee Weapon Attack: +8 to hit, reach 5 ft., one target. Hit: 14 (2d8 + 5) bludgeoning damage."},{"name":"Whirlwind","description":"Each creature in the elemental''s space must make a DC 13 Strength saving throw. On a failure, a target takes 15 (3d8 + 2) bludgeoning damage and is flung up 20 feet away from the elemental in a random direction and knocked prone. If a thrown target strikes an object, such as a wall or floor, the target takes 3 (1d6) bludgeoning damage for every 10 feet it was thrown. If the target is thrown at another creature, that creature must succeed on a DC 13 Dexterity saving throw or take the same damage and be knocked prone.\nIf the saving throw is successful, the target takes half the bludgeoning damage and isn''t flung away or knocked prone."}],"description":"","tags":["Elemental"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
