INSERT INTO public.enemies (slug, name, source, data) VALUES ('young-silver-dragon','Young Silver Dragon','SRD','{"sizeType":"Large dragon, lawful good","armorClass":{"value":18,"note":"natural"},"hitPoints":{"average":168,"formula":"16d10+80"},"speed":"40 ft., fly 80 ft.","abilityScores":{"str":23,"dex":10,"con":21,"int":14,"wis":11,"cha":19},"skills":[{"name":"Arcana","bonus":6},{"name":"History","bonus":6},{"name":"Perception","bonus":8},{"name":"Stealth","bonus":4}],"senses":"darkvision 120 ft., blindsight 30 ft., passive Perception 18","languages":"Common, Draconic","challengeRating":"9","xp":5000,"proficiencyBonus":4,"traits":[],"actions":[{"name":"Multiattack","description":"The dragon makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +10 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage."},{"name":"Claw","description":"Melee Weapon Attack: +10 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage."},{"name":"Breath Weapons","description":"The dragon uses one of the following breath weapons.\nCold Breath. The dragon exhales an icy blast in a 30-foot cone. Each creature in that area must make a DC 17 Constitution saving throw, taking 54 (12d8) cold damage on a failed save, or half as much damage on a successful one.\nParalyzing Breath. The dragon exhales paralyzing gas in a 30-foot cone. Each creature in that area must succeed on a DC 17 Constitution saving throw or be paralyzed for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('young-white-dragon','Young White Dragon','SRD','{"sizeType":"Large dragon, chaotic evil","armorClass":{"value":17,"note":"natural"},"hitPoints":{"average":133,"formula":"14d10+56"},"speed":"40 ft., burrow 20 ft., fly 80 ft., swim 40 ft.","abilityScores":{"str":18,"dex":10,"con":18,"int":6,"wis":11,"cha":12},"skills":[{"name":"Perception","bonus":6},{"name":"Stealth","bonus":3}],"senses":"darkvision 120 ft., blindsight 30 ft., passive Perception 16","languages":"Common, Draconic","challengeRating":"6","xp":2300,"proficiencyBonus":3,"traits":[{"name":"Ice Walk","description":"The dragon can move across and climb icy surfaces without needing to make an ability check. Additionally, difficult terrain composed of ice or snow doesn''t cost it extra movement."}],"actions":[{"name":"Multiattack","description":"The dragon makes three attacks: one with its bite and two with its claws."},{"name":"Bite","description":"Melee Weapon Attack: +7 to hit, reach 10 ft., one target. Hit: 15 (2d10 + 4) piercing damage plus 4 (1d8) cold damage."},{"name":"Claw","description":"Melee Weapon Attack: +7 to hit, reach 5 ft., one target. Hit: 11 (2d6 + 4) slashing damage."},{"name":"Cold Breath","description":"The dragon exhales an icy blast in a 30-foot cone. Each creature in that area must make a DC 15 Constitution saving throw, taking 45 (10d8) cold damage on a failed save, or half as much damage on a successful one."}],"description":"","tags":["Dragon"],"habitat":"","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
INSERT INTO public.enemies (slug, name, source, data) VALUES ('zombie','Zombie','SRD','{"sizeType":"Medium undead, neutral evil","armorClass":{"value":8,"note":"natural armor"},"hitPoints":{"average":22,"formula":"3d8+9"},"speed":"20 ft.","abilityScores":{"str":13,"dex":6,"con":16,"int":3,"wis":6,"cha":5},"skills":[],"senses":"darkvision 60 ft., passive Perception 8","languages":"understands all languages it spoke in life but can''t speak","challengeRating":"1/4","xp":50,"proficiencyBonus":2,"traits":[{"name":"Undead Fortitude","description":"If damage reduces the zombie to 0 hit points, it must make a Constitution saving throw with a DC of 5+the damage taken, unless the damage is radiant or from a critical hit. On a success, the zombie drops to 1 hit point instead."}],"actions":[{"name":"Slam","description":"Melee Weapon Attack: +3 to hit, reach 5 ft., one target. Hit: 4 (1d6 + 1) bludgeoning damage."}],"description":"","tags":["Undead","Chult","ToA"],"habitat":"CHULT","portraitPath":""}'::jsonb) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,source=EXCLUDED.source,data=EXCLUDED.data,updated_at=now();
